import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void simple() {
        // 3 appears 2 > 1.5
        assertEquals(3, new Solution().majorityElement(new int[]{3, 2, 3}));
    }

    @Test
    void longerWithTies() {
        // 2 appears 4 > 3.5
        assertEquals(2, new Solution().majorityElement(new int[]{2, 2, 1, 1, 1, 2, 2}));
    }

    @Test
    void single() {
        assertEquals(5, new Solution().majorityElement(new int[]{5}));
    }

    @Test
    void negativeMajority() {
        assertEquals(-1, new Solution().majorityElement(new int[]{-1, -1, 2}));
    }

    @Test
    void allSame() {
        assertEquals(7, new Solution().majorityElement(new int[]{7, 7, 7, 7}));
    }
}
